220	async function batchFetchIPSSignals(
221	    actionIds: string[],
222	    customerId: string
223	): Promise<Map<string, number>> {
224	    const uniqueActionIds = [...new Set(actionIds.filter(Boolean))];
225	    if (uniqueActionIds.length === 0) return new Map<string, number>();
226	
227	    // Step 1: scope decisions to the tenant via agent ownership.
228	    const { data: decisions, error: decisionsError } = await supabase
229	        .from('fact_decisions')
230	        .select('id, dim_agents!inner(customer_id)')
231	        .eq('dim_agents.customer_id', customerId)
232	        .order('created_at', { ascending: false })
233	        .limit(200);
234	
235	    if (decisionsError) {
236	        console.warn('[scoring] IPS decision scope lookup failed:', decisionsError.message);
237	        return new Map<string, number>();
238	    }
239	
240	    const decisionIds = (decisions ?? []).map((d: any) => d.id).filter(Boolean);
241	    if (decisionIds.length === 0) return new Map<string, number>();
242	
243	    const chunks: string[][] = [];
244	    for (let i = 0; i < decisionIds.length; i += IPS_DECISION_CHUNK_SIZE) {
245	        chunks.push(decisionIds.slice(i, i + IPS_DECISION_CHUNK_SIZE));
246	    }
247	
248	    const chunkResults = await Promise.all(chunks.map(async (chunk, i) => {
249	        const { data, error } = await supabase
250	            .from('fact_outcome_counterfactuals')
251	            .select('unchosen_action_id, counterfactual_est, ips_weight, created_at')
252	            .in('decision_id', chunk)
253	            .in('unchosen_action_id', uniqueActionIds)
254	            .order('created_at', { ascending: false })
255	            .limit(5 * uniqueActionIds.length);
256	
257	        if (error) {
258	            console.warn(
259	                `[scoring] IPS batch query failed (chunk ${i}):`,
260	                error.message,
261	                '| chunk_size:',
262	                chunk.length,
263	                '| action_count:',
264	                uniqueActionIds.length
265	            );
266	            return [] as IPSBatchRow[];
267	        }
268	
269	        return (data ?? []) as IPSBatchRow[];
270	    }));
271	
272	    const deduped = new Map<string, IPSBatchRow>();
273	    for (const row of chunkResults.flat()) {
274	        if (!row.unchosen_action_id || !row.created_at) continue;
275	        const dedupeKey = `${row.unchosen_action_id}:${row.created_at}`;
276	        if (!deduped.has(dedupeKey)) {
277	            deduped.set(dedupeKey, row);
278	        }
279	    }
280	
281	    if (deduped.size === 0) return new Map<string, number>();
282	
283	    const grouped = new Map<string, IPSBatchRow[]>();
284	    for (const row of deduped.values()) {
285	        const actionId = row.unchosen_action_id;
286	        if (!actionId) continue;
287	        const existing = grouped.get(actionId) ?? [];
288	        existing.push(row);
289	        grouped.set(actionId, existing);
290	    }
291	
292	    const signals = new Map<string, number>();
293	    for (const actionId of uniqueActionIds) {
294	        const rows = (grouped.get(actionId) ?? [])
295	            .sort(
296	                (a, b) => new Date(b.created_at ?? 0).getTime() - new Date(a.created_at ?? 0).getTime()
297	            )
298	            .slice(0, 5);
299	
300	        if (rows.length === 0) continue;
301	
302	        const avgEstimate = rows.reduce((sum, r) => sum + (r.counterfactual_est ?? 0), 0) / rows.length;
303	        const avgWeight = rows.reduce((sum, r) => sum + (r.ips_weight ?? 0), 0) / rows.length;
304	        const blendedSignal = Math.max(0, Math.min(1, avgEstimate * avgWeight));
305	        signals.set(actionId, blendedSignal);
306	    }
307	
308	    return signals;
309	}
310	
311	// ── 6-Factor scoring formula ─────────────────────────────────
312	/**
313	 * @param contextMatch — cosine similarity from context-embed.ts.
314	 *   null means exact match (fallback) → treated as 1.0.
315	 */
316	export function computeCompositeScore(
317	    row: ActionScore,
318	    contextMatch: number | null = null,
319	    ipsSignal: number | null = null,
320	    p75ResponseMs: number | null = null,
321	): number {
322	    // Factor 1: Weighted success rate (primary)
323	    // Applied Bayesian smoothing (Laplace / Beta distribution prior):
324	    const rawSuccessRate = row.weighted_success_rate ?? row.raw_success_rate ?? 0;
325	    const n = row.total_attempts ?? 0;
326	
327	    // Bayesian smoothed rate:
328	    // (successes + alpha) / (total + alpha + beta)
329	    const f_success = (rawSuccessRate * n + PRIOR_ALPHA) / (n + PRIOR_ALPHA + PRIOR_BETA);
330	
331	    // Factor 2: Confidence (Wilson-style: n/(n+10))
332	    const f_conf = row.confidence ?? 0;
333	
334	    // Factor 3: Trend delta → normalised to [0,1]
335	    const rawTrend = row.trend_delta ?? 0;
336	    const f_trend = Math.max(0, Math.min(1, (rawTrend + 0.5)));
337	
338	    // Factor 4: Salience — use actual salience_score from fact_outcomes
339	    // if available on the row. Defaults to 1.0 (neutral) if not present.
340	    // mv_action_scores exposes avg_salience_score computed from fact_outcomes.
341	    // If the column is null (old rows), fall back to 1.0 so behaviour is
342	    // unchanged for existing data.
343	    const rawSalience = (row as any).avg_salience_score;
344	    const f_salience = (rawSalience !== null && rawSalience !== undefined)
345	        ? Math.max(0, Math.min(1, Number(rawSalience)))
346	        : 1.0;
347	
348	    // Factor 5: Recency — bonus if last outcome < 24h ago
349	    let f_recency = 0.5;  // neutral default
350	    if (row.last_outcome_at) {
351	        const ageHours = (Date.now() - new Date(row.last_outcome_at).getTime()) / 3_600_000;
352	        f_recency = Math.max(0, Math.min(1, 1 - (ageHours / 168)));  // decay over 7 days
353	    }
354	
355	    // Factor 6: Latency — compare action's avg response time to context baseline p75.
356	    const f_latency = computeLatencyFactor(row.avg_response_ms, p75ResponseMs);
357	
358	    // Context match factor: null → 1.0 (exact match assumed)
359	    const f_context = contextMatch ?? 1.0;
360	
361	    const baseScore = (
362	        W_SUCCESS * f_success +
363	        W_CONF * f_conf +
364	        W_TREND * f_trend +
365	        W_SALIENCE * f_salience +
366	        W_RECENCY * f_recency +
367	        W_LATENCY * f_latency
368	    );
369	
370	    const sampleCount = row.total_attempts ?? 0;
371	    if (sampleCount >= 20 || ipsSignal === null) {
372	        return Math.max(0, Math.min(1, baseScore * f_context));
373	    }
374	
375	    const blendWeight = Math.min(0.10, ((20 - sampleCount) / 20) * 0.10);
376	    const blended = baseScore * (1 - blendWeight) + ipsSignal * blendWeight;
377	
378	    // Final clamp: composite_score must ALWAYS be in [0, 1]
379	    return Math.max(0, Math.min(1, blended * f_context));
380	}
381	
382	function toRecommendation(score: number, isEscalate: boolean): ScoredAction['recommendation'] {
383	    if (isEscalate) return 'escalate';
384	    if (score >= 0.65) return 'recommend';
385	    if (score >= 0.40) return 'neutral';
386	    return 'avoid';
387	}
