389	// ── Main query ────────────────────────────────────────────────
390	async function fetchScoresFromDB(
391	    customerId: string,
392	    contextId: string
393	): Promise<{ scores: ActionScore[]; view_refreshed_at: string | null }> {
394	    const { data, error } = await supabase
395	        .from('mv_action_scores')
396	        .select('*')
397	        .eq('customer_id', customerId)
398	        .eq('context_id', contextId)
399	        .order('weighted_success_rate', { ascending: false });
400	
401	    if (error) throw new Error(`Score query failed: ${error.message}`);
402	
403	    const refreshedAt = data && data.length > 0
404	        ? data[0].view_refreshed_at
405	        : null;
406	
407	    return { scores: (data ?? []) as ActionScore[], view_refreshed_at: refreshedAt };
408	}
409	
410	async function fetchClusterPriors(
411	    customerId: string,
412	    actionIds: string[],
413	): Promise<Map<string, ClusterPrior>> {
414	    const priors = new Map<string, ClusterPrior>();
415	    if (actionIds.length === 0) return priors;
416	
417	    const { data: outcomeRows, error: outcomeError } = await supabase
418	        .from('fact_outcomes')
419	        .select('action_id, semantic_cluster_key, timestamp')
420	        .eq('customer_id', customerId)
421	        .in('action_id', actionIds)
422	        .not('semantic_cluster_key', 'is', null)
423	        .neq('semantic_cluster_key', '')
424	        .order('timestamp', { ascending: false })
425	        .limit(Math.max(actionIds.length * 25, 250));
426	
427	    if (outcomeError || !outcomeRows || outcomeRows.length === 0) {
428	        return priors;
429	    }
430	
431	    const latestClusterByAction = new Map<string, string>();
432	    for (const row of outcomeRows as Array<{ action_id: string; semantic_cluster_key: string | null }>) {
433	        if (!row.semantic_cluster_key) continue;
434	        if (!latestClusterByAction.has(row.action_id)) {
435	            latestClusterByAction.set(row.action_id, row.semantic_cluster_key);
436	        }
437	    }
438	
439	    const uniqueClusters = Array.from(new Set(latestClusterByAction.values()));
440	    if (uniqueClusters.length === 0) return priors;
441	
442	    const { data: clusterRows, error: clusterError } = await supabase
443	        .from('mv_cluster_scores')
444	        .select('semantic_cluster_key, cluster_success_rate, cluster_total_attempts')
445	        .eq('customer_id', customerId)
446	        .in('semantic_cluster_key', uniqueClusters);
447	
448	    if (clusterError || !clusterRows || clusterRows.length === 0) {
449	        return priors;
450	    }
451	
452	    const clusterStats = new Map<string, ClusterPrior>();
453	    for (const row of clusterRows as Array<{
454	        semantic_cluster_key: string;
455	        cluster_success_rate: number | null;
456	        cluster_total_attempts: number | null;
457	    }>) {
458	        const successRate = Math.max(0, Math.min(1, Number(row.cluster_success_rate ?? 0)));
459	        const totalAttempts = Math.max(0, Number(row.cluster_total_attempts ?? 0));
460	        clusterStats.set(row.semantic_cluster_key, {
461	            successRate,
462	            totalAttempts,
463	        });
464	    }
465	
466	    for (const [actionId, clusterKey] of latestClusterByAction.entries()) {
467	        const stats = clusterStats.get(clusterKey);
468	        if (stats) {
469	            priors.set(actionId, stats);
470	        }
471	    }
472	
473	    return priors;
474	}
475	
476	function blendWithClusterPrior(
477	    baseScore: number,
478	    row: ActionScore,
479	    clusterPrior: ClusterPrior | undefined,
480	): number {
481	    if (!clusterPrior) return baseScore;
482	
483	    const sampleCount = Number(row.total_attempts ?? 0);
484	    if (sampleCount >= CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD) {
485	        return baseScore;
486	    }
487	
488	    const deficitWeight = (CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD - sampleCount)
489	        / CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD;
490	    const priorStrength = Math.min(
491	        1,
492	        clusterPrior.totalAttempts / CLUSTER_PRIOR_STRONG_SIGNAL_MIN_SAMPLES,
493	    );
494	    const blendWeight = Math.min(
495	        CLUSTER_PRIOR_MAX_BLEND,
496	        deficitWeight * priorStrength * CLUSTER_PRIOR_MAX_BLEND,
497	    );
498	
499	    const blended = (baseScore * (1 - blendWeight)) + (clusterPrior.successRate * blendWeight);
500	    return Math.max(0, Math.min(1, blended));
501	}
